const request = require('supertest');
const app = require('../server');
const db = require('../db');

jest.mock('../db');

describe('User Routes', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('GET /api/users/search', () => {
    it('returns matching users when query param is provided', async () => {
      db.query.mockResolvedValue({
        rows: [
          { id: 1, name: 'John Doe', email: 'john@example.com' },
          { id: 2, name: 'John Smith', email: 'jsmith@example.com' }
        ]
      });

      const response = await request(app).get('/api/users/search?q=john');

      expect(response.status).toBe(200);
      expect(response.body.length).toBe(2);
      expect(response.body[0].name).toContain('John');
    });

    it('returns empty array when no matches found', async () => {
      db.query.mockResolvedValue({ rows: [] });

      const response = await request(app).get('/api/users/search?q=nonexistent');

      expect(response.status).toBe(200);
      expect(response.body).toEqual([]);
    });

    it('returns 400 when query param is missing', async () => {
      const response = await request(app).get('/api/users/search');

      expect(response.status).toBe(400);
      expect(response.body.error).toBeDefined();
    });

    it('limits results to 10 users', async () => {
      const users = Array.from({ length: 15 }, (_, i) => ({
        id: i + 1,
        name: `User ${i + 1}`,
        email: `user${i + 1}@example.com`
      }));
      db.query.mockResolvedValue({ rows: users });

      const response = await request(app).get('/api/users/search?q=user');

      expect(response.status).toBe(200);
      expect(response.body.length).toBeLessThanOrEqual(10);
    });
  });
});
